            ContentJson = """{"passingScore":80,"questionsPerQuiz":7,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"ax1","text":"Which export is always available on the Exports page, with no connection or setup required?","options":[{"id":"a","text":"The QuickBooks Online journal-entry send"},{"id":"b","text":"The three CSV downloads — Trial Balance, GL Detail, and Journal Summary","isCorrect":true},{"id":"c","text":"A live read-only link into your QuickBooks company file"},{"id":"d","text":"Nothing — exporting requires connecting an accounting provider first"}],"explanation":"The CSV downloads (Trial Balance, GL Detail, Journal Summary) are always available and need no setup. They're the universal way to hand any accountant your books. The QuickBooks send is optional and appears only when your install turns it on and connects QuickBooks."},{"id":"ax2","text":"What does the 'Send to QuickBooks' action actually send?","options":[{"id":"a","text":"A full two-way sync of every transaction"},{"id":"b","text":"The period's per-account net as a single balanced journal entry — one-way, never read back","isCorrect":true},{"id":"c","text":"A PDF of the financial statements"},{"id":"d","text":"Your entire list of accounts, overwriting QuickBooks"}],"explanation":"The send posts the period's per-account net as one balanced journal entry into QuickBooks Online. It's strictly one-way. QuickBooks is never the source of record and nothing syncs back into Forge."},{"id":"ax3","text":"The 'Send to QuickBooks' button refuses and won't send. What is a likely cause?","options":[{"id":"a","text":"The CSV files haven't been downloaded yet"},{"id":"b","text":"An account with a balance isn't matched to a QuickBooks account, or the range overlaps a period you already sent","isCorrect":true},{"id":"c","text":"The trial balance is balanced"},{"id":"d","text":"You picked the Last 30 Days shortcut instead of This Month"}],"explanation":"The send refuses rather than